    spyOn(document, "createElement").and.returnValue({
      getContext: (context: string) => {
        if (context === "webgl2") {
          return {
            getExtension: (extensionName: string) => {
              if (extensionName === "WEBGL_get_buffer_sub_data_async") {
                return {};
              } else if (extensionName === "WEBGL_lose_context") {
                return {loseContext: () => {}};
              }
              return null;
            }
          };
        }
        return null;
      }
    });
  })

