            output += chunk;
          }))

          yield spawn(subscribe(io.stderr).forEach(function*(chunk) {
            errput += chunk;
          }));

          yield;
        }
      } catch (e) {
        error = e;
      }
    });

    await converge(() => expect(output).toContain("listening"));
  })

