      }

      @Query(returns => SampleNumberEnum)
      sampleNumberEnumQuery(
        @Arg("numberEnum", type => SampleNumberEnum) numberEnum: SampleNumberEnum,
      ): SampleNumberEnum {
        enumValue = numberEnum;
        return numberEnum;
      }

      @Query(returns => SampleStringEnum)
      sampleStringEnumQuery(
        @Arg("stringEnum", type => SampleStringEnum) stringEnum: SampleStringEnum,
      ): SampleStringEnum {
        enumValue = stringEnum;
        return stringEnum;
      }

      @Subscription({
        topics: "SAMPLE",
      })
      sampleSubscription(@Root() payload: number): number {
        return payload;
      }
    }

    pubSub = new PubSub();
    ({ typeDefs, resolvers } = await buildTypeDefsAndResolvers({
      resolvers: [SampleResolver],
      authChecker: () => false,
      pubSub,
      container: Container,
      orphanedTypes: [SampleType1],
    }));
    schema = makeExecutableSchema({
      typeDefs,
      resolvers,
    });
    const introspectionResult = await graphql(schema, getIntrospectionQuery());
    schemaIntrospection = (introspectionResult.data as IntrospectionQuery).__schema;
  })

beforeAll(async () => {
    getMetadataStorage().clear();

    @ObjectType()
    class ObjectOne {
      @Field()
      fieldOne: string;
    }
    @ObjectType()
    class ObjectTwo {
      @Field()
      fieldTwo: string;
    }
    @ObjectType()
    class ObjectThree {
      @Field()
      fieldThree: string;
    }

    const OneTwoThreeUnion = createUnionType({
      name: "OneTwoThreeUnion",
      description: "OneTwoThreeUnion description",
      types: () => [ObjectOne, ObjectTwo, ObjectThree],
    });
    const OneTwoThreeUnionFn = createUnionType({
      name: "OneTwoThreeUnionFn",
      description: "OneTwoThreeUnionFn description",
      types: () => [ObjectOne, ObjectTwo, ObjectThree],
    });

    const UnionWithStringResolveType = createUnionType({
      name: "UnionWithStringResolveType",
      types: () => [ObjectOne, ObjectTwo],
      resolveType: value => {
        if ("fieldOne" in value) {
          return "ObjectOne";
        }
        if ("fieldTwo" in value) {
          return "ObjectTwo";
        }
        return;
      },
    });

    const UnionWithClassResolveType = createUnionType({
      name: "UnionWithClassResolveType",
      types: () => [ObjectOne, ObjectTwo],
      resolveType: value => {
        if ("fieldOne" in value) {
          return ObjectOne;
        }
        if ("fieldTwo" in value) {
          return ObjectTwo;
        }
        return;
      },
    });

    @ObjectType()
    class ObjectUnion {
      @Field(type => OneTwoThreeUnion)
      unionField: typeof OneTwoThreeUnion;
    }

    class SampleResolver {
      @Query(returns => OneTwoThreeUnion)
      getObjectOneFromUnion(): typeof OneTwoThreeUnion {
        const oneInstance = new ObjectTwo();
        oneInstance.fieldTwo = "fieldTwo";
        return oneInstance;
      }

      @Query(returns => OneTwoThreeUnionFn)
      getObjectOneFromUnionFn(): typeof OneTwoThreeUnionFn {
        const oneInstance = new ObjectTwo();
        oneInstance.fieldTwo = "fieldTwo";
        return oneInstance;
      }

      @Query()
      getObjectWithUnion(): ObjectUnion {
        const oneInstance = new ObjectTwo();
        oneInstance.fieldTwo = "fieldTwo";
        return {
          unionField: oneInstance,
        };
      }

      @Query(returns => OneTwoThreeUnion)
      getPlainObjectFromUnion(): typeof OneTwoThreeUnion {
        return {
          fieldTwo: "fieldTwo",
        };
      }

      @Query(returns => UnionWithStringResolveType)
      getObjectOneFromStringResolveTypeUnion(): typeof UnionWithStringResolveType {
        return {
          fieldTwo: "fieldTwo",
        };
      }

      @Query(returns => UnionWithClassResolveType)
      getObjectOneFromClassResolveTypeUnion(): typeof UnionWithClassResolveType {
        return {
          fieldTwo: "fieldTwo",
        };
      }
    }

    const schemaInfo = await getSchemaInfo({
      resolvers: [SampleResolver],
    });
    schema = schemaInfo.schema;
    schemaIntrospection = schemaInfo.schemaIntrospection;
    queryType = schemaInfo.queryType;
  })

beforeAll(async () => {
      getMetadataStorage().clear();

      @ObjectType()
      class SampleObject {
        @Field({ nullable: true })
        field?: string;
      }

      @InputType()
      class SampleInput {
        @Field()
        @MaxLength(5)
        stringField: string;

        @Field()
        @Max(5)
        numberField: number;

        @Field({ nullable: true })
        @Min(5)
        optionalField?: number;

        @Field(type => SampleInput, { nullable: true })
        @ValidateNested()
        nestedField?: SampleInput;

        @Field(type => [SampleInput], { nullable: true })
        @ValidateNested({ each: true })
        arrayField?: SampleInput[];
      }

      @ArgsType()
      class SampleArguments {
        @Field()
        @MaxLength(5)
        stringField: string;

        @Field()
        @Max(5)
        numberField: number;

        @Field({ nullable: true })
        @Min(5)
        optionalField?: number;
      }

      @Resolver(of => SampleObject)
      class SampleResolver {
        @Query()
        sampleQuery(@Args() args: SampleArguments): SampleObject {
          argsData = args;
          return {};
        }

        @Mutation()
        sampleMutation(@Arg("input") input: SampleInput): SampleObject {
          argInput = input;
          return {};
        }

        @Mutation()
        mutationWithInputsArray(
          @Arg("inputs", type => [SampleInput]) inputs: SampleInput[],
        ): SampleObject {
          argInput = inputs;
          return {};
        }
      }
      sampleResolver = SampleResolver;

      schema = await buildSchema({
        resolvers: [SampleResolver],
        validate: true,
      });
    })

